css:
.loader {
  color: var(--loader-color, #0891b2);
  height: 54px;
  aspect-ratio: 1;
  position: relative;
  border: 3px solid #0000;
  animation: l11-1 3s linear infinite;
}
.loader:before {
  content: "";
  position: absolute;
  inset: auto 35% 0;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #0891b2);
  animation: l11-0 .5s cubic-bezier(0,500,1,500) infinite;
}
.loader:after {
  content: "";
  position: absolute;
  --b: 4px;
  inset: calc(-1*var(--b)) auto calc(-1*var(--b)) 50%;
  aspect-ratio: 1/cos(30deg);
  translate: -50% 0;
  clip-path: 
    polygon(0 50%,50% -50%,100% 50%,50% 150%,0 50%,
    var(--b) 50%,
    calc(25% + var(--b)*cos(60deg)) calc(100% - var(--b)*sin(60deg)),
    calc(75% - var(--b)*cos(60deg)) calc(100% - var(--b)*sin(60deg)),
    calc(100% - var(--b)) 50%,
    calc(75% - var(--b)*cos(60deg)) calc(var(--b)*sin(60deg)),
    calc(25% + var(--b)*cos(60deg)) calc(var(--b)*sin(60deg)),
    var(--b) 50%);
  background: var(--loader-secondary-color, #22d3ee);
  animation: inherit;
  animation-direction: reverse;
}
@keyframes l11-0 {
  0%,2% {bottom: 0%}
  98%,to {bottom:.1%}
}
@keyframes l11-1 {
  to {rotate: 1turn}
}
